//! Integration tests: h5py-created datasets read with consus-hdf5.
//!
//! ## Purpose
//!
//! These tests verify that consus-hdf5 can correctly parse HDF5 files
//! produced by h5py (Python HDF5 library), covering:
//!
//! - Scalar datasets (int32, float64) using compact or contiguous storage
//! - 1-D arrays (int32, float64, float32, int16, uint8)
//! - 2-D and 3-D contiguous arrays (float64, int32)
//! - Explicitly chunked 1-D and 2-D datasets (int32, float64)
//! - Nested group path navigation
//!
//! ## Fixture
//!
//! `data/h5py_datasets_sample.h5` is generated by running:
//!   `D:\miniforge3\python.exe data/gen_h5py_datasets.py`
//!
//! All tests skip gracefully if the fixture is absent (CI without Python).
//!
//! ## Fixture manifest
//!
//! | Path | Dtype | Shape | Values |
//! |------|-------|-------|--------|
//! | `/scalar_i32`      | int32   | scalar | 42 |
//! | `/scalar_f64`      | float64 | scalar | 3.14159265358979 |
//! | `/array_1d_i32`    | int32   | (8,)   | 0..7 |
//! | `/array_1d_f64`    | float64 | (4,)   | [1.5, 2.5, 3.5, 4.5] |
//! | `/array_2d_f64`    | float64 | (3,4)  | row-major 0.0..11.0 |
//! | `/array_3d_i32`    | int32   | (2,3,4)| 0..23 |
//! | `/array_1d_i16`    | int16   | (6,)   | [10,20,30,40,50,60] |
//! | `/array_1d_u8`     | uint8   | (5,)   | [255,128,64,32,16] |
//! | `/array_1d_f32`    | float32 | (4,)   | [1.0, 2.0, 3.0, 4.0] |
//! | `/chunked_1d_i32`  | int32   | (12,) chunks=(4,) | 0..11 |
//! | `/chunked_2d_f64`  | float64 | (4,6) chunks=(2,3)| row-major 0.0..23.0 |
//! | `/grp/nested_i32`  | int32   | scalar | 77 |
//! | `/grp/nested_f64`  | float64 | (3,)   | [10.0, 20.0, 30.0] |

use consus_hdf5::dataset::StorageLayout;
use consus_hdf5::dataset::layout::DataLayout;
use consus_hdf5::file::{Hdf5File, reader};
use consus_hdf5::object_header::message_types;
use consus_io::MemCursor;
use std::path::PathBuf;

// ---------------------------------------------------------------------------
// Fixture helpers
// ---------------------------------------------------------------------------

fn fixture_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .parent()
        .unwrap()
        .parent()
        .unwrap()
        .join("data")
        .join("h5py_datasets_sample.h5")
}

fn open_fixture() -> Option<Hdf5File<MemCursor>> {
    let path = fixture_path();
    if !path.exists() {
        eprintln!(
            "Skipping: fixture not found at {:?}. Run data/gen_h5py_datasets.py to generate it.",
            path
        );
        return None;
    }
    let bytes = std::fs::read(&path).expect("read fixture file");
    let cursor = MemCursor::from_bytes(bytes);
    Some(Hdf5File::open(cursor).expect("open HDF5 fixture"))
}

/// Read `total_bytes` of raw data from a dataset at `addr`.
///
/// Dispatches on storage layout:
/// - Compact: extracts `compact_data` from the DATA_LAYOUT header message.
/// - Contiguous: reads via `read_contiguous_dataset_bytes`.
/// - Chunked: reads via `read_chunked_dataset_all_bytes`.
fn read_dataset_raw_bytes(file: &Hdf5File<MemCursor>, addr: u64, total_bytes: usize) -> Vec<u8> {
    let dataset = file.dataset_at(addr).expect("read dataset metadata");
    match dataset.layout {
        StorageLayout::Contiguous => {
            let data_addr = dataset
                .data_address
                .expect("contiguous layout must have data_address");
            let mut buf = vec![0u8; total_bytes];
            file.read_contiguous_dataset_bytes(data_addr, 0, &mut buf)
                .expect("read_contiguous_dataset_bytes");
            buf
        }
        StorageLayout::Compact => {
            let header = reader::read_object_header(file.source(), addr, file.context())
                .expect("read object header for compact dataset");
            let msg = reader::find_message(&header, message_types::DATA_LAYOUT)
                .expect("DATA_LAYOUT message must exist in compact dataset object header");
            let layout = DataLayout::parse(&msg.data, file.context())
                .expect("parse DataLayout from compact message bytes");
            let data = layout
                .compact_data
                .expect("compact_data must be populated for compact layout");
            assert!(
                data.len() >= total_bytes,
                "compact_data length {} < expected total_bytes {}",
                data.len(),
                total_bytes
            );
            data[..total_bytes].to_vec()
        }
        StorageLayout::Chunked => file
            .read_chunked_dataset_all_bytes(addr)
            .expect("read_chunked_dataset_all_bytes"),
        other => panic!(
            "unexpected StorageLayout {:?} for read_dataset_raw_bytes at addr {:#x}",
            other, addr
        ),
    }
}

// ---------------------------------------------------------------------------
// Tests: scalar datasets
// ---------------------------------------------------------------------------

/// Read `/scalar_i32` — int32 scalar, value 42.
///
/// ## Invariants
///
/// - Shape is scalar (rank 0, no dimensions).
/// - Four raw bytes decode as little-endian i32 == 42.
#[test]
fn h5py_scalar_i32() {
    let file = match open_fixture() {
        Some(f) => f,
        None => return,
    };

    let addr = file.open_path("/scalar_i32").expect("navigate /scalar_i32");
    let dataset = file.dataset_at(addr).expect("dataset metadata");

    assert!(
        dataset.shape.is_scalar(),
        "/scalar_i32 must be scalar; got shape {:?}",
        dataset.shape
    );

    let raw = read_dataset_raw_bytes(&file, addr, 4);
    let value = i32::from_le_bytes(raw[..4].try_into().unwrap());
    assert_eq!(value, 42, "/scalar_i32 value must be 42; got {}", value);
}

/// Read `/scalar_f64` — float64 scalar, value 3.14159265358979.
///
/// ## Invariants
///
/// - Shape is scalar.
/// - Eight raw bytes decode as little-endian f64 within 1e-14 of 3.14159265358979.
#[test]
fn h5py_scalar_f64() {
    let file = match open_fixture() {
        Some(f) => f,
        None => return,
    };

    let addr = file.open_path("/scalar_f64").expect("navigate /scalar_f64");
    let dataset = file.dataset_at(addr).expect("dataset metadata");

    assert!(
        dataset.shape.is_scalar(),
        "/scalar_f64 must be scalar; got shape {:?}",
        dataset.shape
    );

    let raw = read_dataset_raw_bytes(&file, addr, 8);
    let value = f64::from_le_bytes(raw[..8].try_into().unwrap());
    let expected = 3.14159265358979_f64;
    assert!(
        (value - expected).abs() < 1e-14,
        "/scalar_f64 value {value} differs from expected {expected} by more than 1e-14"
    );
}

// ---------------------------------------------------------------------------
// Tests: 1-D contiguous arrays
// ---------------------------------------------------------------------------

/// Read `/array_1d_i32` — int32 1-D shape=(8,), values 0..7.
///
/// ## Invariants
///
/// - Rank 1, dimension 8.
/// - 32 raw bytes decode as 8 little-endian i32 values equal to [0,1,2,3,4,5,6,7].
#[test]
fn h5py_array_1d_i32() {
    let file = match open_fixture() {
        Some(f) => f,
        None => return,
    };

    let addr = file
        .open_path("/array_1d_i32")
        .expect("navigate /array_1d_i32");
    let dataset = file.dataset_at(addr).expect("dataset metadata");

    let dims = dataset.shape.current_dims();
    assert_eq!(dims.as_slice(), &[8], "/array_1d_i32 must have shape [8]");

    let raw = read_dataset_raw_bytes(&file, addr, 8 * 4);
    let values: Vec<i32> = raw
        .chunks_exact(4)
        .map(|c| i32::from_le_bytes(c.try_into().unwrap()))
        .collect();
    let expected: Vec<i32> = (0..8).collect();
    assert_eq!(values, expected, "/array_1d_i32 values mismatch");
}

/// Read `/array_1d_f64` — float64 1-D shape=(4,), values [1.5, 2.5, 3.5, 4.5].
///
/// ## Invariants
///
/// - Rank 1, dimension 4.
/// - 32 raw bytes decode as 4 little-endian f64 values equal to [1.5, 2.5, 3.5, 4.5] exactly.
#[test]
fn h5py_array_1d_f64() {
    let file = match open_fixture() {
        Some(f) => f,
        None => return,
    };

    let addr = file
        .open_path("/array_1d_f64")
        .expect("navigate /array_1d_f64");
    let dataset = file.dataset_at(addr).expect("dataset metadata");

    let dims = dataset.shape.current_dims();
    assert_eq!(dims.as_slice(), &[4], "/array_1d_f64 must have shape [4]");

    let raw = read_dataset_raw_bytes(&file, addr, 4 * 8);
    let values: Vec<f64> = raw
        .chunks_exact(8)
        .map(|c| f64::from_le_bytes(c.try_into().unwrap()))
        .collect();
    assert_eq!(
        values,
        vec![1.5_f64, 2.5, 3.5, 4.5],
        "/array_1d_f64 values mismatch"
    );
}

