// ---------------------------------------------------------------------------
// Tests: multi-dimensional contiguous arrays
// ---------------------------------------------------------------------------

/// Read `/array_2d_f64` — float64 2-D shape=(3,4), row-major 0.0..11.0.
///
/// ## Invariants
///
/// - Rank 2, dimensions [3, 4], 12 elements total.
/// - 96 raw bytes decode as 12 little-endian f64 values: 0.0, 1.0, …, 11.0 (C order).
#[test]
fn h5py_array_2d_f64() {
    let file = match open_fixture() {
        Some(f) => f,
        None => return,
    };

    let addr = file
        .open_path("/array_2d_f64")
        .expect("navigate /array_2d_f64");
    let dataset = file.dataset_at(addr).expect("dataset metadata");

    let dims = dataset.shape.current_dims();
    assert_eq!(
        dims.as_slice(),
        &[3, 4],
        "/array_2d_f64 must have shape [3, 4]"
    );

    let raw = read_dataset_raw_bytes(&file, addr, 3 * 4 * 8);
    let values: Vec<f64> = raw
        .chunks_exact(8)
        .map(|c| f64::from_le_bytes(c.try_into().unwrap()))
        .collect();
    let expected: Vec<f64> = (0..12).map(|i| i as f64).collect();
    assert_eq!(values, expected, "/array_2d_f64 values mismatch");
}

